class Solution {
public:
    int maxStability(int n, vector<vector<int>>& edges, int k) {
        vector<int> parent(n, -1);
        function<int(int)> find = [&](int x) {
            if (parent[x] == -1) return x;
            return parent[x] = find(parent[x]);
        };
        auto unite = [&](int u, int v) {
            u = find(u); v = find(v);
            if (u == v) return false;
            parent[u] = v; return true;
        };

        vector<int> mustEdges, optEdges;
        for (auto& e : edges) {
            if (e[3]) mustEdges.push_back(e);
            else optEdges.push_back(e);
        }

        int cnt = 0;
        for (auto& e : mustEdges) {
            if (!unite(e[0], e[1])) return -1;
            cnt++;
        }

        if (cnt == n - 1) return mustEdges.back()[2];

        sort(optEdges.begin(), optEdges.end(), [](auto& a, auto& b) {
            return a[2] > b[2];
        });

        int res = 0;
        for (auto& e : optEdges) {
            if (cnt == n - 1) break;
            if (k > 0 && e[2] * 2 > res) {
                k--; e[2] *= 2;
            }
            if (unite(e[0], e[1])) {
                cnt++; res = min(res, e[2]);
            }
        }

        return cnt == n - 1 ? res : -1;
    }
};
